select count(*) from postgres.comments as c, postgres.posts as p, postgres.posthistory as ph, postgres.badges as b, postgres.users as u where u.id = ph.userid and u.id = b.userid and u.id = p.owneruserid and u.id = c.userid and c.creationdate>=timestamp '2010-08-19 09:33:49' and c.creationdate<=timestamp '2014-08-28 06:54:21' and p.posttypeid=1 and p.viewcount>=0 and p.viewcount<=25597 and p.commentcount>=0 and p.commentcount<=11 and p.favoritecount>=0 and u.downvotes<=0 and u.upvotes>=0 and u.upvotes<=123;
